def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    exp_factor = np.exp(-((ratio - a) ** 2) / (b + 1))
                    trig_arg = ratio * b / (a + 0.5)
                    priority += exp_factor * np.sin(trig_arg) * np.tanh(ratio / (b + a))
            priority += (np.sinh(ratio - 7) * np.cos(ratio * 1.3)) ** 2
            for c in range(1, 4):
                priority -= np.log1p(c * ratio) * np.cos(i * c * ratio)
        elif 5 < ratio <= 8:
            for d in range(1, int(np.ceil(ratio)) + 5):
                for e in range(1, d + 4):
                    term = ((ratio - d) ** 4) * np.cos(ratio * d) / (e + 0.3)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio + 1) * 12 - np.tanh(ratio - 5) * 3
            if bin_cap < item * 0.9:
                priority += np.sqrt(item / (bin_cap + 0.1)) * 3.3
            else:
                priority -= np.cos(15 * ratio) * 3
        elif 2 <= ratio <= 5:
            s = 0
            for f in range(1, 15):
                s += ((ratio - 2) ** f) / (f * 2.2) * np.sin(f * ratio) * np.tanh(ratio / (f + 0.1))
            priority = (s * np.sin(9 * ratio)) - np.log(ratio + 0.5) * 7 + np.tanh(3 * (5 - ratio)) * 2.5
            for g in range(1, 6):
                priority += np.sin(g * i * ratio / 2) * ((ratio - 1.2) ** g) / (g ** 1.7)
        elif 1 <= ratio < 2:
            s = 0
            for h in range(1, 20):
                s += ((2 - ratio) ** h) / (h ** 2 + 1) * np.cos(h * ratio * 1.5)
            priority = s * 0.8
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.2)) * 3.7
            else:
                penalty = np.cos(25 * ratio) * 3
            priority += penalty + np.exp(-1.3 / (ratio + 0.03))
            for j in range(1, 7):
                priority += np.sin(j * ratio * i * 0.9) * ((ratio - 0.9) ** j) / (j ** 0.9)
        elif 0.5 <= ratio < 1:
            s = 0
            for k in range(1, 18):
                s += ((1 - ratio) ** k) / (k * 3.7) * np.cos(k * ratio * 2.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.8
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            for l in range(1, 8):
                priority += ((1 - ratio) ** l) * np.sin(l * item * 1.3) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for m in range(1, 14):
                s += ((0.5 - ratio) ** m) / (m * 4.5) * np.cos(m * ratio * 3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.8) * 4
            for n in range(1, 9):
                priority += ((0.5 - ratio) ** n) / (n * 7) * np.cos(item * n * 1.3)
        else:
            s = 0
            for o in range(1, 12):
                s += ((0.2 - ratio) ** o) / (o * 6) * np.sin(o * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for p in range(1, 10):
                priority += ((0.2 - ratio) ** p) / (p * 9) * np.cos(item * p * 1.1)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 7
            for q in range(1, 5):
                priority += np.sin(q * ratio * i * 0.7) * ((ratio - 0.7) ** q) / (q + 1)
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
            for r in range(1, 4):
                priority -= np.cos(r * ratio * i * 1.3) * 0.4
        for s in range(1, 5):
            if (i + s) % 4 == 0:
                priority += np.sin(ratio * (i + s) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + s) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
